import React from "react";

const HeroServices = () => {
  return (
    <>
      <div className="">
        <h1 className="text-[170px] text-center font-black uppercase tracking-widest bg-gradient-to-b from-white/15 to-transparent bg-clip-text text-transparent">
          Our Services
        </h1>
        <div className="w-[180px] mx-auto h-[50px] rounded-full text-[22px] font-bold text-center flex justify-center items-center bg-black border-[1px] border-white/20">
          Our Services
        </div>
      </div>
    </>
  );
};

export default HeroServices;
